# Importing necessary libraries for input/output
import sys

# Function to prompt user for input and return a list of integers
def get_input():
    try:
        nums = []  # Empty list to store user inputs
        while True:
            try:
                num = int(input("Enter a number (0-9): "))
                if num <= 0 or num > 9:
                    print("Invalid input. Please enter a number between 0 and 9.")
